from collections import defaultdict, deque

def detect_tool_loops(agent):
    tool_history = defaultdict(deque)
    max_history = 10

    def wrapper(run):
        result = run()
        call_log = agent._last_tool_calls or []

        for call in call_log[-max_history:]:
            tool_name = call.get('name', 'unknown')
            tool_history[tool_name].append(call)

            if len(tool_history[tool_name]) > 3:
                recent_calls = list(tool_history[tool_name])[-3:]
                if all(c.get('args') == recent_calls[0].get('args') for c in recent_calls):
                    raise LoopDetected(f"Tool '{tool_name}' repeating with identical args")

        return result

    return wrapper

import hashlib

class StateLoopDetector:
    def __init__(self, window=5):
        self.state_hashes = deque(maxlen=window)
        self.window = window

    def check(self, agent_state):
        state_str = str(agent_state)
        state_hash = hashlib.md5(state_str.encode()).hexdigest()

        if state_hash in self.state_hashes:
            repeat_count = self.state_hashes.count(state_hash)
            if repeat_count >= 2:
                raise LoopDetected(f"State hash {state_hash} repeated {repeat_count} times")

        self.state_hashes.append(state_hash)

class TokenBudgetDetector:
    def __init__(self, max_tokens=10000):
        self.total_tokens = 0
        self.max_tokens = max_tokens

    def track_call(self, tool_call):
        # Estimate tokens: tool name (10) + args (avg 50 per arg)
        tokens = 10 + len(str(tool_call.get('args', {}))) // 4
        self.total_tokens += tokens

        if self.total_tokens > self.max_tokens:
            raise LoopDetected(f"Exceeded token budget: {self.total_tokens}/{self.max_tokens}")

        return tokens

