def safe_agent_run(agent):
    call_cache = set()

    original_call = agent._call_tool

    def deduped_call(tool_name, args):
        args_str = json.dumps(args, sort_keys=True)
        call_key = f"{tool_name}:{hash(args_str)}"

        if call_key in call_cache:
            print(f"Skipping duplicate call: {call_key}")
            return {'cached': True, 'result': 'skipped duplicate'}

        call_cache.add(call_key)
        return original_call(tool_name, args)

    agent._call_tool = deduped_call
    return agent

class IterationGuard:
    def __init__(self, max_calls=20):
        self.call_count = 0
        self.max_calls = max_calls

    def __call__(self, func):
        def wrapper(*args, **kwargs):
            nonlocal self
            self.call_count += 1
            if self.call_count > self.max_calls:
                return {
                    'error': 'Max tool calls exceeded',
                    'call_count': self.call_count,
                    'suggestion': 'Consider simplifying task or providing more context'
                }
            return func(*args, **kwargs)
        return wrapper

