class ProgressChecker:
    def __init__(self):
        self.last_output_hash = None
        self.progress_threshold = 0.1  # 10% token change minimum

    def check_progress(self, new_output):
        if self.last_output_hash is None:
            self.last_output_hash = hash(new_output)
            return True

        current_hash = hash(new_output)
        if current_hash == self.last_output_hash:
            raise LoopDetected("No progress detected in output")

        self.last_output_hash = current_hash
        return True

# Wrap agent output
